// default import(=autoAnimate);先按 minimal 建出直接子节点,之后的增删改序由 WAAPI 自动过渡
import autoAnimate from 'https://cdn.jsdelivr.net/npm/@formkit/auto-animate@0.10.0/+esm';
const list = document.getElementById('list'); list.style.cssText = 'display:grid;gap:8px;padding:12px';
for (const text of data.items ?? []) { const item = document.createElement('div'); item.textContent = text; item.style.cssText = 'padding:8px 12px;border:1px solid #d0d7de;border-radius:6px'; list.appendChild(item); }
autoAnimate(list, data.options ?? {});

boot.widget:
// default import;WAAPI 无样式注入,直接作用于 shadow 里的父容器
import autoAnimate from 'https://cdn.jsdelivr.net/npm/@formkit/auto-animate@0.10.0/+esm';
const list = document.createElement('ul'); shadowRoot.appendChild(list);
(data.items ?? []).forEach(t => { const li = document.createElement('li'); li.textContent = t; list.appendChild(li); });
autoAnimate(list, data.options ?? {}); // 模块级 window scroll/ResizeObserver 是全局但无害,不破坏 shadow 隔离

